def merge_within(pairs, d):
    if not pairs:
        return []

    merged = [sorted(pairs)[0]]

    for start, end in sorted(pairs)[1:]:
        last_start, last_end = merged[-1]

        if start - last_end <= d:
            merged[-1] = [last_start, max(end, last_end)]
        else:
            merged.append([start, end])

    return merged
